patch:
--- a/comparator.v
+++ b/comparator.v
@@ -1,11 +1,11 @@
 module comparator_64bit(
   input [63:0] x,
   input [63:0] y,
   output reg eq, lt, gt
 );

-  always @(x) begin
+  always @(x or y) begin
     eq = (x == y);
     lt = (x < y);
     gt = (x > y);
   end

 endmodule

before_code:
module comparator_64bit(
  input [63:0] x,
  input [63:0] y,
  output reg eq, lt, gt
);

  always @(x) begin
    eq = (x == y);
    lt = (x < y);
    gt = (x > y);
  end

endmodule

after_code:
module comparator_64bit(
  input [63:0] x,
  input [63:0] y,
  output reg eq, lt, gt
);

  always @(x or y) begin
    eq = (x == y);
    lt = (x < y);
    gt = (x > y);
  end

endmodule
